create table user_notifications (
    notif_id       number generated by default as identity not null enable,
    notif_type     varchar2(50 byte),
    event_ref_id   varchar2(100 byte),
    title          varchar2(255 byte),
    body           varchar2(2000 byte),
    user_type      varchar2(30 byte),
    user_id        varchar2(100 byte),
    status         varchar2(20 byte) default 'UNREAD',
    app_id         number,
    page_id        number,
    target_url     varchar2(4000 byte),
    channel        varchar2(30 byte) default 'APP',
    sent_at        timestamp(6) default systimestamp,
    read_at        timestamp(6),
    created        timestamp(6) default systimestamp,
    created_by     varchar2(100 byte),
    target_item_id varchar2(100 byte)
);

alter table user_notifications add primary key ( notif_id )
    using index enable;

